#include "turbidity.h"
#include <Arduino.h>
#define TURB_PIN 34
static float _ntu=0,_v=0;static unsigned long _l=0;
void turbidity_setup(){Serial.println("[turb] OK");}
void turbidity_loop(){if(millis()-_l<500)return;_l=millis();int r=0;for(int i=0;i<10;i++)r+=analogRead(TURB_PIN);_v=r/10.0*3.3/4095.0;_ntu=-1120.4*_v*_v+5742.3*_v-4353.8;if(_ntu<0)_ntu=0;}
float turbidity_get_ntu(){return _ntu;}
float turbidity_get_voltage(){return _v;}
